INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07880', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若研究者在寄出的說明信函當中表示此為無須具名之問卷，但卻又在回郵信封的背面左下角以淡色鉛筆 做了編號，此種作法違反的是何種研究倫理守則？', '["妨礙研究對象之自主性", "欺瞞研究對象", "傷害研究對象", "侵犯研究對象之權益"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07881', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者依據相關理論並發展出以下之研究假設：乳房切除手術婦女病患在術後的沮喪程度與其所感受之 社會支持程度有關，並依此發展問卷項目，此種研究過程稱為：', '["歸納推理", "演繹推理", "因果推理", "相關推理 請依下列研究情境回答第29至第34題 該研究者在架構研究概念時，運用了某些心理適應之相關理論，並參閱一些相關之研究以做為發展問卷之依 據，問卷設計完成之後，該研究者分別請了兩位資深的醫院社會工作師，以及兩位在大學教授醫療社會工作的 老師，協助檢視問卷之設計內容。問卷回收並予以過錄之後，從研究當中的幾個主要變項之資料分析獲得下列 的相關係數矩陣（均為零階相關係數） 年齡  教育程度  年所得收入  家人支持程度 年齡 教育程度  .30 年所得收入  .70  .64 家人支持程度  －.65  .10  －.25 沮喪程度  .80  －.20  －.60  －.75 註：家人支持程度與沮喪程度皆以量表進行評量，量表總得分越高代表家人支持程度越強； 量表總得分越高代表沮喪狀況越嚴重；年齡與年所得收入皆為實際年齡與實際年收入； 教育程度則以接受正式教育之年數表之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07882', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '該研究者所使用的效度檢驗程序為：', '["專家效度（expert validity）", "效標關聯效度（criterion-related validity）", "建構效度（construct validity）", "預測效度（predictive validity）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07883', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在「沮喪量表」的發展上，研究者是以15題有關沮喪狀況出現頻率的問項設計而成，並以⑴從未出現⑵很 少出現⑶有時出現⑷經常出現⑸總是出現之五點尺度進行測量。試問此種單一項目問題之測量層次為：', '["等比或比率（ratio）", "等距（interval）", "等級或次序（ordinal）", "無法判斷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07884', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若該研究者嘗試進行上一題中某個單一項目問題測量結果的描述統計分析，則下列何者較不適當？', '["平均數", "有效百分比", "累加百分比", "眾數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07885', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若研究者將術後婦女病患之家人支持程度界定為：家人支持程度係以本研究之「家人支持量表」進行測 量，此種定義為：', '["概念性定義", "語意性定義", "操作性定義", "延伸性定義"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07886', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從相關矩陣之資料分析顯示，家人支持程度與沮喪程度之間呈現的皮爾遜積差相關係數（Pearson’s r）為 －0.75，此一結果代表：', '["家人的支持程度越高，婦女病患沮喪的程度也相對越高", "家人的支持程度越高，婦女病患沮喪的程度則相對越低", "家人的高度支持是降低婦女病患沮喪的原因", "家人的支持程度與婦女病患沮喪程度之間關係微弱"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07887', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若依據某個心理適應理論之論述，顯示受到危機創傷之婦女的沮喪程度會與其教育程度、年齡、家人的 支持程度等變項具有因果關係。研究者為了要驗證此一因果模型，她應該使用下列何種統計分析程序？', '["因素分析（factor analysis）", "聚類分析（cluster analysis）", "內容分析（content analysis）", "多重迴歸分析（multiple regression analysis）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07888', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關因果模型之敘述，何者正確？①共變為因果關係之先決條件  ②實驗性研究設計旨在驗證因果關', '["依變項在產生變化的時間順序上先於自變項", "因果關係中的依變項與自變項應直接有關  ⑤在實 驗性之研究設計中可明確擬定研究假設", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07889', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在某安養機構中，社會工作師長期觀察老年住民，他發現家屬前來探視陪伴老年人的時間越多，則老年 人住在安養院的生活適應程度也越高，因此他認為「老年住民的心理狀態與其家屬的支持程度有關」。 此種推理過程為：', '["邏輯推理", "演繹推理", "歸納推理", "統計推理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
